        int numQueries = queries.length;
        long[] results = new long[numQueries];

        for (int i = 0; i < numQueries; i++) {
            long l = queries[i][0];
            long r = queries[i][1];
            long k = queries[i][2];

            // 1. Identify all even numbers in nums[l..r]
            Set<Long> removedEvens = new HashSet<>();
            for (int j = (int) l; j <= r; j++) {
                if (nums[j] % 2 == 0) {
                    removedEvens.add(nums[j]);
                }
            }

            // 2. Determine the target value: the k-th smallest positive even number not in removedEvens.
            // The positive even numbers are 2, 4, 6, 8, 10, 12, ...
            // The i-th positive even number is 2 * i (where i starts from 1).

            // We are looking for the smallest integer X = 2 * m (m >= 1) such that:
            // 1. X is not in removedEvens.
            // 2. The count of positive even numbers <= X that are NOT in removedEvens is exactly k.

            // Let's consider the potential answer X = 2 * m.
            // The total count of positive even numbers <= X is m.
            // The count of removed even numbers <= X is the number of elements in removedEvens that are <= X.
            // The remaining count <= X is m - (count of removed evens <= X).

            // We are looking for the smallest m >= 1 such that:
            // m - (count of removed evens <= 2*m) >= k

            // Since the target value can be up to roughly 2 * (10^9 + 10^5), binary search is appropriate
            // on the multiplier m (where the answer is 2*m).

            // Maximum possible answer: If k is large (10^9) and no evens are removed, the answer is 2*k = 2*10^9.
            // If many evens are removed, the required m will be slightly larger.
            // Max possible m is around 10^9 + (number of evens in nums, which is <= 10^5).
            // A safe upper bound for m is 2 * 10^9 + 10^5. Let's use 3 * 10^9 for safety in long arithmetic.

            long lowM = 1;
            // Max possible answer is related to k_i, which is up to 10^9. 
            // If no evens are removed, answer is 2*k.
            // If all evens up to 2*k are removed, we need an answer > 2*k.
            // The maximum number of removed evens is N <= 10^5.
            // So, the maximum m we might need is roughly k + N, which is ~10^9 + 10^5.
            long highM = 2_000_000_000L + 100005L; // Safe upper bound for m
            long ansM = highM;

            while (lowM <= highM) {
                long currentM = lowM + (highM - lowM) / 2;
                long currentX = 2 * currentM;

                // Count how many removed evens are <= currentX
                int removedCount = 0;
                for (long ev : removedEvens) {
                    if (ev <= currentX) {
                        removedCount++;
                    }
                }

                // Remaining count of evens <= currentX
                long remainingCount = currentM - removedCount;

                if (remainingCount >= k) {
                    // currentM might be the answer, try for a smaller one
                    ansM = currentM;
                    highM = currentM - 1;
                } else {
                    // remainingCount < k, need a larger X (larger M)
                    lowM = currentM + 1;
                }
            }

            results[i] = 2 * ansM;
        }

        return results;
    }
